 37→public class ParameterListWrappingRule :
 38→    StandardRule(
 39→        id = "parameter-list-wrapping",
 40→        usesEditorConfigProperties =
 41→            setOf(
 42→                CODE_STYLE_PROPERTY,
 43→                INDENT_SIZE_PROPERTY,
 44→                INDENT_STYLE_PROPERTY,
 45→                MAX_LINE_LENGTH_PROPERTY,
 46→            ),
 47→    ) {
 48→    private var codeStyle = CODE_STYLE_PROPERTY.defaultValue
 49→    private var indentConfig = IndentConfig.DEFAULT_INDENT_CONFIG
 50→    private var maxLineLength = MAX_LINE_LENGTH_PROPERTY.defaultValue
 51→
 52→    override fun beforeFirstNode(editorConfig: EditorConfig) {
 53→        codeStyle = editorConfig[CODE_STYLE_PROPERTY]
 54→        maxLineLength = editorConfig[MAX_LINE_LENGTH_PROPERTY]
 55→        indentConfig = IndentConfig(
 56→            indentStyle = editorConfig[INDENT_STYLE_PROPERTY],
 57→            tabWidth = editorConfig[INDENT_SIZE_PROPERTY],
 58→        )
 59→        if (indentConfig.disabled) {
 60→            stopTraversalOfAST()
 61→        }
 62→    }
 63→
 64→    override fun beforeVisitChildNodes(
 65→        node: ASTNode,
 66→        autoCorrect: Boolean,
 67→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 68→    ) {
 69→        when (node.elementType) {
 70→            NULLABLE_TYPE -> wrapNullableType(node, emit, autoCorrect)
 71→            VALUE_PARAMETER_LIST -> {
 72→                if (node.needToWrapParameterList()) {
 73→                    wrapParameterList(node, emit, autoCorrect)
 74→                }
 75→            }
 76→        }
 77→    }
 78→
 79→    private fun wrapNullableType(
 80→        node: ASTNode,
 81→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 82→        autoCorrect: Boolean,
 83→    ) {
 84→        require(node.elementType == NULLABLE_TYPE)
 85→        node
 86→            .takeUnless {
 87→                // skip when max line length is not exceedd
 88→                (node.column - 1 + node.textLength) <= maxLineLength
 89→            }?.findChildByType(FUNCTION_TYPE)
 90→            ?.findChildByType(VALUE_PARAMETER_LIST)
 91→            ?.takeIf { it.findChildByType(VALUE_PARAMETER) != null }
 92→            ?.takeUnless { it.textContains('\n') }
 93→            ?.let {
 94→                node
 95→                    .children()
 96→                    .forEach {
 97→                        when (it.elementType) {
 98→                            LPAR -> {
 99→                                emit(
100→                                    it.startOffset,
101→                                    "Parameter of nullable type should be on a separate line (unless the type fits on a single line)",
102→                                    true,
103→                                )
104→                                if (autoCorrect) {
105→                                    it.upsertWhitespaceAfterMe("\n${indentConfig.indent}")
106→                                }
107→                            }
108→                            RPAR -> {
109→                                emit(it.startOffset, errorMessage(it), true)
110→                                if (autoCorrect) {
111→                                    it.upsertWhitespaceBeforeMe("\n")
112→                                }
113→                            }
114→                        }
115→                    }
116→            }
117→    }
118→
119→    private fun ASTNode.needToWrapParameterList() =
120→        when {
121→            hasNoParameters() -> false
122→            isPartOfFunctionLiteralInNonKtlintOfficialCodeStyle() -> false
123→            isFunctionTypeWrappedInNullableType() -> false
124→            textContains('\n') -> true
125→            codeStyle == ktlint_official && containsAnnotatedParameter() -> true
126→            exceedsMaxLineLength() -> true
127→            else -> false
128→        }
129→
130→    private fun ASTNode.hasNoParameters(): Boolean {
131→        require(elementType == VALUE_PARAMETER_LIST)
132→        return firstChildNode?.treeNext?.elementType == RPAR
133→    }
134→
135→    private fun ASTNode.isPartOfFunctionLiteralInNonKtlintOfficialCodeStyle(): Boolean {
136→        require(elementType == VALUE_PARAMETER_LIST)
137→        return codeStyle != ktlint_official && treeParent?.elementType == FUNCTION_LITERAL
138→    }
139→
140→    private fun ASTNode.isFunctionTypeWrappedInNullableType(): Boolean {
141→        require(elementType == VALUE_PARAMETER_LIST)
142→        return treeParent.elementType == FUNCTION_TYPE && treeParent?.treeParent?.elementType == NULLABLE_TYPE
143→    }
144→
145→    private fun ASTNode.containsAnnotatedParameter(): Boolean {
146→        require(elementType == VALUE_PARAMETER_LIST)
147→        return this.children()
148→            .filter { it.elementType == VALUE_PARAMETER }
149→            .any { it.isAnnotated() }
150→    }
151→
152→    private fun ASTNode.isAnnotated() =
153→        findChildByType(ElementType.MODIFIER_LIST)
154→            ?.children()
155→            .orEmpty()
156→            .any { it.elementType == ElementType.ANNOTATION_ENTRY }
157→
158→    private fun wrapParameterList(
159→        node: ASTNode,
160→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
161→        autoCorrect: Boolean,
162→    ) {
163→        val newIndentLevel = getNewIndentLevel(node)
164→        node
165→            .children()
166→            .forEach { child -> wrapParameterInList(newIndentLevel, child, emit, autoCorrect) }
167→    }
168→
169→    private fun getNewIndentLevel(node: ASTNode): Int {
170→        val currentIndentLevel = indentConfig.indentLevelFrom(node.indent(false))
171→        return when {
172→            // IDEA quirk:
173→            // fun <
174→            //     T,
175→            //     R> test(
176→            //     param1: T
177→            //     param2: R
178→            // )
179→            // instead of
180→            // fun <
181→            //     T,
182→            //     R> test(
183→            //         param1: T
184→            //         param2: R
185→            //     )
186→            currentIndentLevel > 0 && node.hasTypeParameterListInFront() -> currentIndentLevel - 1
187→
188→            else -> currentIndentLevel
189→        }
190→    }
191→
192→    private fun wrapParameterInList(
193→        newIndentLevel: Int,
194→        child: ASTNode,
195→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
196→        autoCorrect: Boolean,
197→    ) {
198→        val indent = "\n" + indentConfig.indent.repeat(newIndentLevel)
199→        when (child.elementType) {
200→            LPAR -> {
201→                val prevLeaf = child.prevLeaf()
202→                if (prevLeaf is PsiWhiteSpace && prevLeaf.textContains('\n')) {
203→                    emit(child.startOffset, errorMessage(child), true)
204→                    if (autoCorrect) {
205→                        prevLeaf.delete()
206→                    }
207→                }
208→            }
209→            VALUE_PARAMETER,
210→            RPAR,
211→            -> {
212→                // aiming for
213→                // ... LPAR
214→                // <line indent + indentSize> VALUE_PARAMETER...
215→                // <line indent> RPAR
216→                val intendedIndent =
217→                    if (child.elementType == VALUE_PARAMETER) {
218→                        indent + indentConfig.indent
219→                    } else {
220→                        indent
221→                    }
222→                val prevLeaf = child.prevLeaf()
223→                if (prevLeaf is PsiWhiteSpace) {
224→                    if (prevLeaf.getText().contains("\n")) {
225→                        // The current child is already wrapped to a new line. Checking and fixing the
226→                        // correct size of the indent is the responsibility of the IndentationRule.
227→                        return
228→                    } else {
229→                        // The current child needs to be wrapped to a newline.
230→                        emit(child.startOffset, errorMessage(child), true)
231→                        if (autoCorrect) {
232→                            // The indentation is purely based on the previous leaf only. Note that in
233→                            // autoCorrect mode the indent rule, if enabled, runs after this rule and
234→                            // determines the final indentation. But if the indent rule is disabled then the
235→                            // indent of this rule is kept.
236→                            (prevLeaf as LeafPsiElement).rawReplaceWithText(intendedIndent)
237→                        }
238→                    }
239→                } else {
240→                    // Insert a new whitespace element in order to wrap the current child to a new line.
241→                    emit(child.startOffset, errorMessage(child), true)
242→                    if (autoCorrect) {
243→                        child.treeParent.addChild(PsiWhiteSpaceImpl(intendedIndent), child)
244→                    }
245→                }
246→                // Indentation of child nodes need to be fixed by the IndentationRule.
247→            }
248→        }
249→    }
250→
251→    private fun ASTNode.exceedsMaxLineLength() = (column - 1 + textLength) > maxLineLength && !textContains('\n')
252→
253→    private fun errorMessage(node: ASTNode) =
254→        when (node.elementType) {
255→            LPAR -> """Unnecessary newline before "(""""
256→            VALUE_PARAMETER ->
257→                "Parameter should start on a newline"
258→            RPAR -> """Missing newline before ")""""
259→            else -> throw UnsupportedOperationException()
260→        }
261→
262→    private fun ASTNode.hasTypeParameterListInFront(): Boolean {
263→        val parent = this.treeParent
264→        val typeParameterList =
265→            if (parent.elementType == PRIMARY_CONSTRUCTOR) {
266→                parent.prevSibling { it.elementType == TYPE_PARAMETER_LIST }
267→            } else {
268→                parent.children().firstOrNull { it.elementType == TYPE_PARAMETER_LIST }
269→            }
270→        val typeListNode =
271→            typeParameterList
272→                ?: parent.psi.collectDescendantsOfType<KtTypeArgumentList>().firstOrNull()?.node
273→                ?: return false
274→        return typeListNode.children().any { it.isWhiteSpaceWithNewline() }
275→    }
276→}
277→
278→public val PARAMETER_LIST_WRAPPING_RULE_ID: RuleId = ParameterListWrappingRule().ruleId
279→

