132→private fun ASTNode.getElementsPerLine(): List<ParsedLine> {
133→    val parsedLines = mutableListOf<ParsedLine>()
134→    val lines = text.split("\n")
135→    var offset = 0
136→    for (line in lines) {
137→        val elements = mutableListOf<ASTNode>()
138→        var el = psi.findElementAt(offset)?.node
139→        while (el != null && el.startOffset < offset + line.length) {
140→            elements.add(el)
141→            el = el.nextLeaf()
142→        }
143→        parsedLines.add(ParsedLine(line, offset, elements))
144→        offset += line.length + 1 // +1 for the newline which is stripped due to the splitting of the lines
145→    }
146→    return parsedLines
147→}
148→
149→private data class ParsedLine(
150→    val line: String,
151→    val offset: Int,
152→    val elements: List<ASTNode>,
153→) {
154→    fun lineLength(ignoreBackTickedIdentifier: Boolean): Int {
155→        return if (ignoreBackTickedIdentifier) {
156→            line.length - totalLengthBacktickedElements()
157→        } else {
158→            line.length
159→        }
160→    }
161→
162→    private fun totalLengthBacktickedElements(): Int {
163→        return elements
164→            .filterIsInstance(PsiElement::class.java)
165→            .filter { it.text.matches(BACKTICKED_IDENTIFIER_REGEX) }
166→            .sumOf(PsiElement::getTextLength)
167→    }
168→
169→    private companion object {
170→        val BACKTICKED_IDENTIFIER_REGEX = Regex("`.*`")
171→    }
172→}
173→
174→internal class RangeTree(seq: List<Int> = emptyList()) {
175→    private var emptyArrayView = ArrayView(0, 0)
176→    private var arr: IntArray = seq.toIntArray()
177→
178→    init {
179→        if (arr.isNotEmpty()) {
180→            arr.reduce { p, n -> require(p <= n) { "Input must be sorted" }; n }
181→        }
182→    }
183→
184→    // runtime: O(log(n)+k), where k is number of matching points
185→    // space: O(1)
186→    fun query(
187→        vmin: Int,
188→        vmax: Int,
189→    ): ArrayView {
190→        var r = arr.size - 1
191→        if (r == -1 || vmax < arr[0] || arr[r] < vmin) {
192→            return emptyArrayView
193→        }
194→        // binary search for min(arr[l] >= vmin)
195→        var l = 0
196→        while (l < r) {
197→            val m = (r + l) / 2
198→            if (vmax < arr[m]) {
199→                r = m - 1
200→            } else if (arr[m] < vmin) {
201→                l = m + 1
202→            } else {
203→                // arr[l] ?<=? vmin <= arr[m] <= vmax ?<=? arr[r]
204→                if (vmin <= arr[l]) break else l++ // optimization
205→                r = m
206→            }
207→        }
208→        if (l > r || arr[l] < vmin) {
209→            return emptyArrayView
210→        }
211→        // find max(k) such as arr[k] < vmax
212→        var k = l
213→        while (k < arr.size) {
214→            if (arr[k] >= vmax) {
215→                break
216→            }
217→            k++
218→        }
219→        return ArrayView(l, k)
220→    }
221→
222→    fun isEmpty(): Boolean = arr.isEmpty()
223→
224→    inner class ArrayView(private var l: Int, private val r: Int) {
225→        val size: Int = r - l
226→
227→        fun get(i: Int): Int {
228→            if (i < 0 || i >= size) {
229→                throw IndexOutOfBoundsException()
230→            }
231→            return arr[l + i]
232→        }
233→
234→        inline fun forEach(cb: (v: Int) -> Unit) {
235→            var i = 0
236→            while (i < size) {
237→                cb(get(i++))
238→            }
239→        }
240→
241→        override fun toString(): String {
242→            if (l == r) {
243→                return "[]"
244→            }
245→            val sb = StringBuilder("[")
246→            var i = l
247→            while (i < r) {
248→                sb.append(arr[i]).append(", ")
249→                i++
250→            }
251→            sb.replace(sb.length - 2, sb.length, "")
252→            sb.append("]")
253→            return sb.toString()
254→        }
255→    }
256→}
