 61→public fun ASTNode.firstChildLeafOrSelf(): ASTNode {
 62→    var n = this
 63→    if (n.firstChildNode != null) {
 64→        do {
 65→            n = n.firstChildNode
 66→        } while (n.firstChildNode != null)
 67→        return n
 68→    }
 69→    return n
 70→}
